import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a request to begin capturing a turf.
 * Includes the virtual_room_id of the turf the user is standing in.
 */
export class StartTurfCaptureComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(virtualRoomId: number) {
        this._data = [virtualRoomId];
        console.log('[Turf] Claim packet sent for vRoomId:', virtualRoomId);
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        // no-op
    }
}
